4603	\begin{lemma}\leanok
4604	[Image of an affine basic open under an open immersion of affines]
4605	  \label{lem:image_basicOpen_of_affine}
4606	  \lean{AlgebraicGeometry.Scheme.Modules.image_basicOpen_of_affine}
4607	  \textit{Project-bespoke: pure-geometry image helper, stated with the immersion opaque.}
4608	  Let \(j : \Spec S \to \Spec R\) be an open immersion and \(f' \in S\). Then the image of the basic
4609	  open \(D(f')\) under \(j\) is the \(\Spec R\) scheme basic open of the transported global section
4610	  \((j.\mathrm{appIso}\,\top)^{-1}\bigl((\Gamma\Spec\text{-iso}_S)^{-1}\,f'\bigr)\):
4611	  \[
4612	    j\,''^{U}\,D(f') = (\Spec R).\mathrm{basicOpen}\,
4613	      \bigl((j.\mathrm{appIso}\,\top)^{-1}\,((\Gamma\Spec\text{-iso}_S)^{-1}\,f')\bigr).
4614	  \]
4615	\end{lemma}
4616	\begin{proof}
4617	  Rewrite \(D(f')\) as the \(\Spec S\) scheme basic open of the global structure section
4618	  \((\Gamma\Spec\text{-iso}_S)^{-1}\,f'\) (Mathlib's \(\mathrm{basicOpen\_eq\_of\_affine}\)), then push
4619	  it across \(j\) by the scheme-image-of-a-basic-open identity (Mathlib's
4620	  \(\mathrm{Scheme.image\_basicOpen}\)), which sends a basic open to the basic open of the
4621	  \(\mathrm{appIso}\)-transported section. The immersion \(j\) is kept abstract so the rewrite does not
4622	  unfold a concrete composite.
4623	\end{proof}
