4642	\begin{lemma}\leanok
4643	[Image of an affine basic open as an intersection with the range]
4644	  \label{lem:image_basicOpen_eq_inf}
4645	  \lean{AlgebraicGeometry.Scheme.Modules.image_basicOpen_eq_inf}
4646	  \uses{lem:image_basicOpen_of_affine}
4647	  \textit{Project-bespoke: rewrites the $f'$-locus image as range $\sqcap$ basic open.}
4648	  Let \(j : \Spec S \to \Spec R\) be an open immersion, \(f' \in S\), and \(g \in \Gamma(\Spec R, \top)\)
4649	  a global section whose restriction to \(j\,''^{U}\,\top\) equals the \(\mathrm{appIso}\)-transport of
4650	  \(f'\). Then
4651	  \[
4652	    j\,''^{U}\,D(f') = (j\,''^{U}\,\top) \sqcap (\Spec R).\mathrm{basicOpen}\,g .
4653	  \]
4654	\end{lemma}
4655	\begin{proof}
4656	  \uses{lem:image_basicOpen_of_affine}
4657	  By \cref{lem:image_basicOpen_of_affine}, \(j\,''^{U}\,D(f')\) is the basic open of the
4658	  \(\mathrm{appIso}\)-transport of \(f'\); the transport hypothesis identifies that transport with the
4659	  restriction of \(g\) to \(j\,''^{U}\,\top\), and the structure-sheaf basic-open-of-a-restriction
4660	  identity (Mathlib's \(\mathrm{Scheme.basicOpen\_res}\)) turns the basic open of a restricted section
4661	  into the intersection of the restriction domain \(j\,''^{U}\,\top\) with the basic open of \(g\).
4662	\end{proof}
